const update = $input.first().json;
const message = update.message || update.edited_message;

if (!message) {
  return [{ json: { error: 'No message found', skip: true } }];
}

const chatId = String(message.chat?.id || '');
const userId = String(message.from?.id || '');
const messageId = String(message.message_id || '');
const username = message.from?.username || message.from?.first_name || '';

const isVoice = !!message.voice;
const isText  = !!message.text;
const messageType = isVoice ? 'voice' : (isText ? 'text' : 'unsupported');

return [{
  json: {
    chatId,
    userId,
    messageId,
    username,
    isVoice,
    isText,
    messageType,
    fileId:      message.voice?.file_id || null,
    textContent: message.text || null,
    startTime:   Date.now(),
    timestamp:   new Date().toISOString()
  }
}];

const msgData = $('Extract Message Data').first().json;
const raw = $input.first().json;

// PostgREST returns array; pick first row
const biz = Array.isArray(raw) ? raw[0] : raw;
const businessFound = !!(biz && biz.business_id);
const isActive = biz?.status === 'active';

return [{
  json: {
    ...msgData,
    businessId:           businessFound ? biz.business_id : null,
    businessName:         businessFound ? biz.business_name : null,
    websiteUrl:           businessFound ? (biz.website_url || null) : null,
    wcConsumerKey:        businessFound ? (biz.wc_consumer_key_encrypted || null) : null,
    wcConsumerSecret:     businessFound ? (biz.wc_consumer_secret_encrypted || null) : null,
    businessFound,
    isActive
  }
}];

const bizData = $('Process Business Lookup').first().json;
const whisper = $input.first().json;

// Whisper returns { text: '...' } directly
const text = whisper.text || whisper.body?.text || '';

if (!text || text.trim() === '') {
  return [{
    json: {
      ...bizData,
      queryText: '',
      inputSource: 'voice',
      transcription: null,
      error: 'Voice transcription empty or failed'
    }
  }];
}

return [{
  json: {
    ...bizData,
    queryText:     text.trim(),
    inputSource:   'voice',
    transcription: text.trim()
  }
}];

const bizData = $('Process Business Lookup').first().json;
const text    = bizData.textContent || '';

return [{
  json: {
    ...bizData,
    queryText:   text,
    inputSource: 'text',
    transcription: null
  }
}];

