const gpt = $input.first().json;

// ── Get query text from whichever branch ran ──
let ctx = {};
try { ctx = $('Process Transcription').first().json; } catch(e) {}
if (!ctx.queryText) { try { ctx = $('Use Text Directly').first().json; } catch(e) {} }

const q = (ctx.queryText || ctx.textContent || '').toLowerCase().trim();

// ══════════════════════════════════════════════════════════════
// KEYWORD RULES — 100% reliable, runs first, no GPT dependency
// ══════════════════════════════════════════════════════════════
let intent = null;
let timePeriod = 'today';

// Report keywords
if (/report|weekly report|monthly report|top product|best seller|summary/.test(q)) {
  intent = 'report_request';
  if      (/last week|pichle hafte/.test(q))     timePeriod = 'last week';
  else if (/last month|pichle mahine/.test(q))   timePeriod = 'last month';
  else if (/this month|is mahine|monthly/.test(q)) timePeriod = 'this month';
  else                                             timePeriod = 'this week';
}
// Inventory keywords
else if (/inventory|stock/.test(q)) {
  intent = 'inventory_check';
}
// Sales keywords
else if (/sale|revenue|order|earn|income|kitni|bikri|aaj ki/.test(q)) {
  intent = 'sales_query';
  if      (/last week|pichle hafte/.test(q))     timePeriod = 'last week';
  else if (/last month|pichle mahine/.test(q))   timePeriod = 'last month';
  else if (/this month|is mahine|monthly/.test(q)) timePeriod = 'this month';
  else if (/this week|is hafte|weekly/.test(q))  timePeriod = 'this week';
  else if (/yesterday|kal ka|kal ki/.test(q))    timePeriod = 'yesterday';
  else                                             timePeriod = 'today';
}

// ══════════════════════════════════════════════════════════════
// GPT FALLBACK — only if keywords matched nothing
// ══════════════════════════════════════════════════════════════
if (!intent) {
  try {
    const content = gpt.choices?.[0]?.message?.content || gpt.message?.content || gpt.text || '';
    if (content) {
      const cleaned = content.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
      const m = cleaned.match(/\{[\s\S]*\}/);
      if (m) {
        const parsed = JSON.parse(m[0]);
        if (parsed.intent) {
          intent = parsed.intent;
          timePeriod = parsed.entities?.time_period || 'today';
        }
      }
    }
  } catch(e) {}
}

// Final fallback
const validIntents = ['sales_query','inventory_check','report_request','general_inquiry'];
if (!intent || !validIntents.includes(intent)) intent = 'general_inquiry';

// ══════════════════════════════════════════════════════════════
// SPECIFIC DATE extract
// ══════════════════════════════════════════════════════════════
let specificDate = null;
const months = { jan:1,feb:2,mar:3,apr:4,may:5,jun:6,jul:7,aug:8,sep:9,oct:10,nov:11,dec:12 };
const dm = q.match(/(\d{1,2})\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\s*(\d{4})?/i);
const md = q.match(/(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\s+(\d{1,2})\s*(\d{4})?/i);
if (dm) {
  const day = dm[1].padStart(2,'0');
  const mon = String(months[dm[2].toLowerCase()]).padStart(2,'0');
  const yr  = dm[3] || new Date().getFullYear();
  specificDate = `${yr}-${mon}-${day}`;
  if (intent === 'general_inquiry') intent = 'sales_query';
} else if (md) {
  const day = md[2].padStart(2,'0');
  const mon = String(months[md[1].toLowerCase()]).padStart(2,'0');
  const yr  = md[3] || new Date().getFullYear();
  specificDate = `${yr}-${mon}-${day}`;
  if (intent === 'general_inquiry') intent = 'sales_query';
}

// ══════════════════════════════════════════════════════════════
// PRODUCT NAME extract (inventory only)
// ══════════════════════════════════════════════════════════════
let productName = null;
if (intent === 'inventory_check') {
  const stripped = q
    .replace(/\b(inventory|stock|check|maal|available|konsa|product|kitna|ka|ki|show|dekho|batao|karo|lao|dy|do|bta|bhi|detail|price|info|of|the|mujhe|mujhy|mjy)\b/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (stripped.length >= 2) productName = stripped;
}

return [{
  json: {
    ...ctx,
    intent,
    confidence:   0.9,
    timePeriod,
    specificDate,
    productName,
    entities: { time_period: timePeriod, specific_date: specificDate, product_name: productName }
  }
}];

const d  = $input.first().json;
const tp = (d.timePeriod || 'today').toLowerCase();
const specificDate = d.specificDate || null;

const now = new Date();

let startDate, endDate, label;

// ── Specific date — highest priority ──────────────────────────
if (specificDate && /^\d{4}-\d{2}-\d{2}$/.test(specificDate)) {
  startDate = specificDate;
  const next = new Date(specificDate); next.setDate(next.getDate() + 1);
  endDate = next.toISOString().split('T')[0];
  label = specificDate;
}
// ── Standard periods ──────────────────────────────────────────
else if (tp.includes('yesterday')) {
  const y = new Date(now); y.setDate(y.getDate() - 1);
  startDate = y.toISOString().split('T')[0];
  const nxt = new Date(now);
  endDate = nxt.toISOString().split('T')[0];
  label = 'Yesterday';
} else if (tp.includes('last week')) {
  const lw = new Date(now); lw.setDate(lw.getDate() - 7);
  startDate = lw.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'Last 7 Days';
} else if (tp.includes('last month')) {
  const lm = new Date(now); lm.setMonth(lm.getMonth() - 1);
  startDate = lm.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'Last 30 Days';
} else if (tp.includes('week')) {
  const dow = now.getDay() || 7;
  const mon = new Date(now); mon.setDate(now.getDate() - dow + 1);
  startDate = mon.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'This Week';
} else if (tp.includes('month')) {
  startDate = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'This Month';
} else {
  // Today
  startDate = now.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'Today';
}

return [{ json: { ...d, startDate, endDate, periodLabel: label } }];

const raw   = $input.first().json;
const rows  = Array.isArray(raw.body) ? raw.body : (Array.isArray(raw) ? raw : []);
const d     = $('Prepare Sales Query').first().json;
const ctx   = $('Parse Classification').first().json;
const period   = d.periodLabel || 'Today';
const currency = rows[0]?.currency || 'PKR';

const totalOrders   = rows.length;
const totalSales    = rows.reduce((s, r) => s + (parseFloat(r.total)||0) - (parseFloat(r.total_refunded)||0), 0);
const grossRevenue  = rows.reduce((s, r) => s + (parseFloat(r.total)||0), 0);
const totalRefunded = rows.reduce((s, r) => s + (parseFloat(r.total_refunded)||0), 0);
const avgOrderValue = totalOrders > 0 ? totalSales / totalOrders : 0;
const fmt = n => n.toLocaleString('en', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

let response;
if (totalOrders === 0) {
  response = `📊 *Sales — ${period}*\n\nNo orders found for this period.`;
} else {
  response = [
    `📊 *Sales Analytics — ${period}*`,
    ``,
    `✅ Total Orders:    ${totalOrders}`,
    `💰 Net Sales:       ${currency} ${fmt(totalSales)}`,
    `📦 Gross Revenue:   ${currency} ${fmt(grossRevenue)}`,
    totalRefunded > 0 ? `↩️ Refunded:        ${currency} ${fmt(totalRefunded)}` : null,
    `📈 Avg Order Value: ${currency} ${fmt(avgOrderValue)}`
  ].filter(Boolean).join('\n');
}

return [{ json: { ...ctx, ...d, response } }];

const raw  = $input.first().json;
let rows = Array.isArray(raw.body) ? raw.body : (Array.isArray(raw) ? raw : []);
const d  = $('Parse Classification').first().json;
const productName = d.productName || null;

if (productName) {
  const words = productName.toLowerCase().trim().split(/\s+/).filter(w => w.length >= 2);
  rows = rows.filter(p => {
    const n = (p.name || '').toLowerCase();
    return words.every(w => n.includes(w));
  });
} else {
  rows = rows.filter(p => (p.stock_quantity ?? 0) <= 5);
}

if (rows.length === 0) {
  const msg = productName
    ? `📦 *Inventory Search*\n\nNo product found matching: "${productName}"`
    : `📦 *Inventory*\n\nAll products are well stocked. No items with stock 0-5.`;
  return [{ json: { ...d, response: msg } }];
}

const lines = rows.map(p => {
  const qty = p.stock_quantity ?? 0;
  const dot = qty === 0 ? '🔴' : (qty <= 5 ? '🟡' : '🟢');
  return `${dot} ${p.name}\n   Stock: ${qty}  |  Price: PKR ${p.price || '—'}`;
});

const title = productName
  ? `📦 *Product Search: "${productName}"*`
  : `📦 *Low Stock Alert (0-5 units)*`;

return [{ json: { ...d, response: `${title}\n\n${lines.join('\n\n')}` } }];

const d  = $input.first().json;
const tp = (d.timePeriod || 'this week').toLowerCase();

let startDate, endDate, label;
const now = new Date();

if (tp.includes('last month')) {
  const lm = new Date(now); lm.setMonth(lm.getMonth() - 1);
  startDate = new Date(lm.getFullYear(), lm.getMonth(), 1).toISOString().split('T')[0];
  endDate   = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  label = 'Last Month';
} else if (tp.includes('month')) {
  startDate = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'This Month';
} else if (tp.includes('last week')) {
  const lw = new Date(now); lw.setDate(lw.getDate() - 7);
  startDate = lw.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'Last 7 Days';
} else {
  // This week — Monday to today
  const dow = now.getDay() || 7;
  const mon = new Date(now); mon.setDate(now.getDate() - dow + 1);
  startDate = mon.toISOString().split('T')[0];
  const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate() + 1);
  endDate = tomorrow.toISOString().split('T')[0];
  label = 'This Week';
}

return [{ json: { ...d, startDate, endDate, periodLabel: label } }];

const raw  = $input.first().json;
const rows = Array.isArray(raw.body) ? raw.body : (Array.isArray(raw) ? raw : []);
const d    = $('Prepare Report Query').first().json;
const ctx  = $('Parse Classification').first().json;
const period = d.periodLabel || 'This Week';

if (rows.length === 0) {
  return [{ json: { ...ctx, ...d, response: `📈 *Report — ${period}*\n\nNo sales data found for this period.` } }];
}

const map = {};
for (const r of rows) {
  const n = r.product_name || 'Unknown';
  if (!map[n]) map[n] = { units: 0, revenue: 0 };
  map[n].units   += parseInt(r.quantity) || 0;
  map[n].revenue += parseFloat(r.total)  || 0;
}

const sorted = Object.entries(map).sort((a, b) => b[1].units - a[1].units).slice(0, 5);
const totalRevenue = Object.values(map).reduce((s, v) => s + v.revenue, 0);
const lines = sorted.map(([n, v], i) =>
  `${i+1}. ${n}\n   Units: ${v.units}  |  Revenue: PKR ${v.revenue.toFixed(2)}`
);

const response = `📈 *Sales Report — ${period}*\n💰 Total Revenue: PKR ${totalRevenue.toFixed(2)}\n\n🏆 *Top Products:*\n${lines.join('\n\n')}`;
return [{ json: { ...ctx, ...d, response } }];

const d = $input.first().json;
const response = `👋 Hello ${d.username || 'there'}!\n\nI can help you with:\n• 📊 Sales — "What are my sales today?"
• 📦 Inventory — "Check my inventory"
• 📈 Reports — "Show this week's report"

Just type or send a voice message!`;
return [{ json: { ...d, response } }];

// $input already contains the output from whichever format node ran.
// Every format node spreads full context (chatId, businessId, intent, etc.)
const d = $input.first().json;
const elapsed = d.startTime ? Date.now() - d.startTime : null;

return [{
  json: {
    response:         d.response         || 'Sorry, I could not process your request.',
    chatId:           d.chatId           || '',
    userId:           d.userId           || '',
    messageId:        d.messageId        || '',
    messageType:      d.messageType      || 'text',
    businessId:       d.businessId       || null,
    rawText:          d.textContent      || null,
    transcription:    d.transcription    || null,
    intent:           d.intent           || 'general_inquiry',
    entities:         d.entities         || {},
    processingTimeMs: elapsed
  }
}];

const d = $input.first().json;
const text = (d.textContent || d.text || '').trim().toUpperCase();
const isSendEmail = text === 'SEND EMAIL' || text.includes('SEND EMAIL');
return [{ json: { ...d, isSendEmail } }];

const alertsRaw = $('Fetch Pending Inventory Alerts').all().map(i => i.json);
const supplierRaw = $('Fetch Supplier').all().map(i => i.json);
const chatId = $('Check SEND EMAIL').first().json.chatId;

// alertsRaw directly array of items hai
const alerts = alertsRaw.filter(a => a.business_id); // valid rows filter karo

if (alerts.length === 0) {
  return [{ json: { skip: true, chatId, noAlerts: true } }];
}

const supplier = supplierRaw[0] || { name: 'Supplier', email: 'supplier@example.com' };
const today = new Date().toISOString().split('T')[0];
const businessId = alerts[0].business_id;

const outOfStock = alerts.filter(a => a.status === 'out_of_stock');
const lowStock = alerts.filter(a => a.status === 'low');

let emailBody = `Dear ${supplier.name},\n\n`;
emailBody += `We need to reorder the following products:\n\n`;

if (outOfStock.length > 0) {
  emailBody += `OUT OF STOCK:\n`;
  outOfStock.forEach((p, i) => {
    emailBody += `${i+1}. ${p.product_name} — Please send ASAP\n`;
  });
  emailBody += `\n`;
}

if (lowStock.length > 0) {
  emailBody += `LOW STOCK:\n`;
  lowStock.forEach((p, i) => {
    emailBody += `${i+1}. ${p.product_name} — Current: ${p.stock_quantity} units\n`;
  });
  emailBody += `\n`;
}

emailBody += `Please confirm availability and expected delivery date.\n\nRegards,\nBizFlow AI`;

return [{
  json: {
    businessId,
    supplierEmail: supplier.email,
    supplierName: supplier.name,
    emailSubject: `Reorder Required — ${today}`,
    emailBody,
    totalItems: alerts.length,
    chatId,
    skip: false
  }
}];

